SELECT A1.ID, A1.SHIP_NAME, A2.ID shipvoyageItemId, A2.IMP_EXP, A2.TRADE_TYPE, A2.LOAD_UNLOAD, A2.VOYAGE, A2.CUSTOMER_ID, A2.CUSTOMER_NAME, SUM(A3.TON) TON FROM T_DIS_SHIPVOYAGE A1 LEFT JOIN T_DIS_SHIPVOYAGE_ITEM A2 ON A1.ID = A2.SHIPVOYAGE_ID LEFT JOIN T_BUS_HANDOVERLIST A3 ON A3.SHIPVOYAGE_ITEM_ID = A2.ID WHERE A2.ID IS NOT NULL
AND A2.ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND A1.SHIP_NAME LIKE #{shipName_like}
AND A2.VOYAGE LIKE #{voyage_like}
GROUP BY A1.ID, A1.SHIP_NAME, A2.ID, A2.IMP_EXP, A2.TRADE_TYPE, A2.LOAD_UNLOAD, A2.VOYAGE, A2.CUSTOMER_ID, A2.CUSTOMER_NAME

